local function send_json_response(status, data)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json; charset=utf-8"
    ngx.say(cjson.encode(data))
    return ngx.exit(status)
end

local function connect_redis()
    local red, err = redis:new()
    if not red then
        return nil, "Failed to create Redis instance: " .. (err or "unknown")
    end

    red:set_timeout(REDIS_TIMEOUT)

    local ok, conn_err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis at " .. REDIS_HOST .. ":" .. REDIS_PORT .. " - " .. (conn_err or "unknown")
    end

    if REDIS_PASSWORD and REDIS_PASSWORD ~= "" then
        local auth_ok, auth_err = red:auth(REDIS_PASSWORD)
        if not auth_ok then
            return nil, "Redis authentication failed: " .. (auth_err or "unknown")
        end
    end

    return red, nil
end

local function close_redis(red)
    if not red then
        return
    end
    local ok, err = red:set_keepalive(REDIS_KEEPALIVE_TIMEOUT, REDIS_KEEPALIVE_POOL_SIZE)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
        red:close()
    end
end

local function parse_request_body()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    if not body then
        return nil, "Empty request body"
    end

    local ok, data = pcall(cjson.decode, body)
    if not ok then
        return nil, "Invalid JSON in request body: " .. tostring(data)
    end

    return data, nil
end

local function validate_command(cmd)
    if not cmd or type(cmd) ~= "string" or cmd == "" then
        return false, "Command must be a non-empty string"
    end

    local lower_cmd = string.lower(cmd)

    if BLOCKED_COMMANDS[lower_cmd] then
        return false, "Command '" .. cmd .. "' is blocked for security reasons"
    end

    if not ALLOWED_COMMANDS[lower_cmd] then
        return false, "Command '" .. cmd .. "' is not in the allowed commands list"
    end

    return true, nil
end

local function format_redis_result(result)
    if type(result) == "table" then
        local formatted = {}
        for i, v in ipairs(result) do
            if type(v) == "userdata" then
                -- ngx.null
                formatted[i] = cjson.null
            else
                formatted[i] = v
            end
        end
        return formatted
    elseif type(result) == "userdata" then
        return cjson.null
    else
        return result
    end
end

local function convert_arg_type(arg)
    if type(arg) == "string" then
        local num = tonumber(arg)
        if num and string.match(arg, "^%-?%d+%.?%d*$") then
            return num
        end
    end
    return arg
end

-- Execute a single Redis command
local function execute_command(red, command, args)
    local cmd = string.lower(command)

    -- Special handling for eval
    if cmd == "eval" then
        if not args or #args < 2 then
            return nil, "EVAL requires at least script and numkeys arguments"
        end
        local script = args[1]
        local numkeys = tonumber(args[2])
        if not numkeys then
            return nil, "EVAL second argument (numkeys) must be a number"
        end

        local eval_args = {}
        for i = 3, #args do
            table.insert(eval_args, args[i])
        end

        local result, err = red:eval(script, numkeys, unpack(eval_args))
        if not result then
            return nil, "EVAL error: " .. (err or "unknown")
        end
        return format_redis_result(result), nil
    end

    -- Special handling for evalsha
    if cmd == "evalsha" then
        if not args or #args < 2 then
            return nil, "EVALSHA requires at least sha1 and numkeys arguments"
        end
        local sha1 = args[1]
        local numkeys = tonumber(args[2])
        if not numkeys then
            return nil, "EVALSHA second argument (numkeys) must be a number"
        end

        local evalsha_args = {}
        for i = 3, #args do
            table.insert(evalsha_args, args[i])
        end

        local result, err = red:evalsha(sha1, numkeys, unpack(evalsha_args))
        if not result then
            return nil, "EVALSHA error: " .. (err or "unknown")
        end
        return format_redis_result(result), nil
    end

    -- Generic command execution
    local redis_func = red[cmd]
    if not redis_func then
        return nil, "Redis command '" .. command .. "' is not supported by the Redis library"
    end

    local result, err
    if args and #args > 0 then
        result, err = redis_func(red, unpack(args))
    else
        result, err = redis_func(red)
    end

    if not result then
        return nil, "Redis error: " .. (err or "unknown")
    end

    return format_redis_result(result), nil
end

-- Execute a pipeline of commands
local function execute_pipeline(red, commands)
    red:init_pipeline()

    local cmd_list = {}
    for i, cmd_entry in ipairs(commands) do
        local command = cmd_entry.command or cmd_entry.cmd
        local args = cmd_entry.args or {}

        if not command then
            return nil, "Pipeline command #" .. i .. " is missing 'command' field"
        end

        local valid, val_err = validate_command(command)
        if not valid then
            return nil, "Pipeline command #" .. i .. ": " .. val_err
        end

        local cmd = string.lower(command)

        -- For eval in pipeline
        if cmd == "eval" then
            if #args < 2 then
                return nil, "Pipeline command #" .. i .. ": EVAL requires at least script and numkeys"
            end
            local script = args[1]
            local numkeys = tonumber(args[2])
            if not numkeys then
                return nil, "Pipeline command #" .. i .. ": EVAL numkeys must be a number"
            end
            local eval_args = {}
            for j = 3, #args do
                table.insert(eval_args, args[j])
            end
            red:eval(script, numkeys, unpack(eval_args))
        elseif cmd == "evalsha" then
            if #args < 2 then
                return nil, "Pipeline command #" .. i .. ": EVALSHA requires at least sha1 and numkeys"
            end
            local sha1 = args[1]
            local numkeys = tonumber(args[2])
            if not numkeys then
                return nil, "Pipeline command #" .. i .. ": EVALSHA numkeys must be a number"
            end
            local evalsha_args = {}
            for j = 3, #args do
                table.insert(evalsha_args, args[j])
            end
            red:evalsha(sha1, numkeys, unpack(evalsha_args))
        else
            local redis_func = red[cmd]
            if not redis_func then
                return nil, "Pipeline command #" .. i .. ": unsupported command '" .. command .. "'"
            end
            if #args > 0 then
                redis_func(red, unpack(args))
            else
                redis_func(red)
            end
        end

        table.insert(cmd_list, command)
    end

    local results, err = red:commit_pipeline()
    if not results then
        return nil, "Pipeline commit error: " .. (err or "unknown")
    end

    local formatted_results = {}
    for i, result in ipairs(results) do
        local entry = {
            command = cmd_list[i] or ("command_" .. i),
            index = i
        }
        if type(result) == "table" and result[1] == false then
            entry.error = tostring(result[2])
            entry.success = false
        else
            entry.result = format_redis_result(result)
            entry.success = true
        end
        table.insert(formatted_results, entry)
    end

    return formatted_results, nil
end

-- Parse command from query string (GET requests)
local function handle_get_request()
    local args = ngx.req.get_uri_args()
    local command = args.cmd or args.command
    local raw_args = args.args

    if not command then
        return send_json_response(ngx.HTTP_BAD_REQUEST, {
            success = false,
            error = "Missing 'cmd' or 'command' query parameter",
            usage = {
                single = "GET /redis?cmd=get&args=mykey",
                multiple_args = "GET /redis?cmd=set&args=mykey&args=myvalue",
                eval = "GET /redis?cmd=eval&args=return 1&args=0"
            }
        })
    end

    local valid, val_err = validate_command(command)
    if not valid then
        return send_json_response(ngx.HTTP_FORBIDDEN, {
            success = false,
            error = val_err
        })
    end

    -- Normalize args to a table
    local cmd_args = {}
    if raw_args then
        if type(raw_args) == "table" then
            cmd_args = raw_args
        else
            cmd_args = { raw_args }
        end
    end

    -- Convert numeric strings to numbers where appropriate
    for i, arg in ipairs(cmd_args) do
        cmd_args[i] = convert_arg_type(arg)
    end

    local red, conn_err = connect_redis()
    if not red then
        return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
            success = false,
            error = conn_err
        })
    end

    local result, exec_err = execute_command(red, command, cmd_args)
    close_redis(red)

    if exec_err then
        return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
            success = false,
            error = exec_err,
            command = command,
            args = cmd_args
        })
    end

    return send_json_response(ngx.HTTP_OK, {
        success = true,
        command = command,
        args = cmd_args,
        result = result
    })
end

-- Handle POST requests with JSON body
local function handle_post_request()
    local data, parse_err = parse_request_body()
    if not data then
        return send_json_response(ngx.HTTP_BAD_REQUEST, {
            success = false,
            error = parse_err,
            usage = {
                single_command = {
                    command = "GET",
                    args = { "mykey" }
                },
                eval_command = {
                    command = "EVAL",
                    args = { "return redis.call('get', KEYS[1])", 1, "mykey" }
                },
                pipeline = {
                    pipeline = {
                        { command = "SET", args = { "key1", "value1" } },
                        { command = "GET", args = { "key1" } }
                    }
                }
            }
        })
    end

    -- Check if this is a pipeline request
    if data.pipeline and type(data.pipeline) == "table" then
        local red, conn_err = connect_redis()
        if not red then
            return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
                success = false,
                error = conn_err
            })
        end

        -- Select database if specified
        if data.db then
            local db_num = tonumber(data.db)
            if db_num then
                local ok, sel_err = red:select(db_num)
                if not ok then
                    close_redis(red)
                    return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
                        success = false,
                        error = "Failed to select database " .. db_num .. ": " .. (sel_err or "unknown")
                    })
                end
            end
        end

        local results, pipe_err = execute_pipeline(red, data.pipeline)
        close_redis(red)

        if pipe_err then
            return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
                success = false,
                error = pipe_err
            })
        end

        return send_json_response(ngx.HTTP_OK, {
            success = true,
            pipeline = true,
            count = #results,
            results = results
        })
    end

    -- Single command execution
    local command = data.command or data.cmd
    local cmd_args = data.args or {}

    if not command then
        return send_json_response(ngx.HTTP_BAD_REQUEST, {
            success = false,
            error = "Missing 'command' or 'cmd' field in JSON body"
        })
    end

    local valid, val_err = validate_command(command)
    if not valid then
        return send_json_response(ngx.HTTP_FORBIDDEN, {
            success = false,
            error = val_err
        })
    end

    if type(cmd_args) ~= "table" then
        cmd_args = { cmd_args }
    end

    local red, conn_err = connect_redis()
    if not red then
        return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
            success = false,
            error = conn_err
        })
    end

    -- Select database if specified
    if data.db then
        local db_num = tonumber(data.db)
        if db_num then
            local ok, sel_err = red:select(db_num)
            if not ok then
                close_redis(red)
                return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
                    success = false,
                    error = "Failed to select database " .. db_num .. ": " .. (sel_err or "unknown")
                })
            end
        end
    end

    local result, exec_err = execute_command(red, command, cmd_args)
    close_redis(red)

    if exec_err then
        return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
            success = false,
            error = exec_err,
            command = command,
            args = cmd_args
        })
    end

    return send_json_response(ngx.HTTP_OK, {
        success = true,
        command = command,
        args = cmd_args,
        result = result
    })
end

