local function handle_info_request()
    local allowed_list = {}
    for cmd, _ in pairs(ALLOWED_COMMANDS) do
        table.insert(allowed_list, cmd)
    end
    table.sort(allowed_list)

    local blocked_list = {}
    for cmd, _ in pairs(BLOCKED_COMMANDS) do
        table.insert(blocked_list, cmd)
    end
    table.sort(blocked_list)

    return send_json_response(ngx.HTTP_OK, {
        success = true,
        service = "Redis Management Interface",
        version = "1.0.0",
        redis = {
            host = REDIS_HOST,
            port = REDIS_PORT
        },
        endpoints = {
            {
                method = "GET",
                path = "/redis",
                description = "Execute a single Redis command via query parameters",
                parameters = {
                    cmd = "Redis command name (required)",
                    args = "Command arguments (can be repeated for multiple args)"
                },
                examples = {
                    "GET /redis?cmd=ping",
                    "GET /redis?cmd=get&args=mykey",
                    "GET /redis?cmd=set&args=mykey&args=myvalue",
                    "GET /redis?cmd=hset&args=myhash&args=field1&args=value1"
                }
            },
            {
                method = "POST",
                path = "/redis",
                description = "Execute single command or pipeline via JSON body",
