                    eval_script = '{"command": "EVAL", "args": ["return redis.call(\'set\', KEYS[1], ARGV[1])", 1, "mykey", "hello"]}',
                    pipeline = '{"pipeline": [{"command": "SET", "args": ["k1", "v1"]}, {"command": "GET", "args": ["k1"]}]}',
                    with_db = '{"command": "GET", "args": ["mykey"], "db": 2}'
                }
            },
            {
                method = "GET",
                path = "/redis/info",
                description = "Show this help information"
            },
            {
                method = "GET",
                path = "/redis/health",
                description = "Check Redis connection health"
            }
        },
        allowed_commands = allowed_list,
        blocked_commands = blocked_list
    })
end

-- Health check endpoint
local function handle_health_request()
    local red, conn_err = connect_redis()
    if not red then
        return send_json_response(ngx.HTTP_SERVICE_UNAVAILABLE, {
            success = false,
            status = "unhealthy",
            error = conn_err,
            redis = {
                host = REDIS_HOST,
                port = REDIS_PORT
            }
        })
    end

    local result, err = red:ping()
    if not result then
        close_redis(red)
        return send_json_response(ngx.HTTP_SERVICE_UNAVAILABLE, {
            success = false,
            status = "unhealthy",
            error = "Redis PING failed: " .. (err or "unknown")
        })
    end

    -- Get some server info
    local info_result, info_err = red:info("server")
    local server_info = {}
    if info_result and type(info_result) == "string" then
        for line in info_result:gmatch("[^\r\n]+") do
            local key, value = line:match("^([^:]+):(.+)$")
            if key and value then
                if key == "redis_version" or key == "uptime_in_seconds" or
                   key == "connected_clients" or key == "used_memory_human" then
                    server_info[key] = value
                end
            end
        end
    end

    local dbsize, _ = red:dbsize()
    close_redis(red)

    return send_json_response(ngx.HTTP_OK, {
        success = true,
        status = "healthy",
        ping = tostring(result),
        redis = {
            host = REDIS_HOST,
            port = REDIS_PORT,
            dbsize = dbsize and tonumber(dbsize) or nil,
            server = server_info
        },
        timestamp = ngx.now()
    })
end

-- Main router
local function main()
    local method = ngx.req.get_method()
    local uri = ngx.var.uri

    -- Route: /redis/info or /redis/help
    if uri == "/redis/info" or uri == "/redis/help" then
        return handle_info_request()
    end

    -- Route: /redis/health
    if uri == "/redis/health" then
        return handle_health_request()
    end

    -- Route: /redis
    if uri == "/redis" or uri == "/redis/" then
        if method == "GET" then
            return handle_get_request()
        elseif method == "POST" then
            return handle_post_request()
        else
            return send_json_response(ngx.HTTP_NOT_ALLOWED, {
                success = false,
                error = "Method " .. method .. " not allowed. Use GET or POST.",
                allowed_methods = { "GET", "POST" }
            })
        end
    end

    return send_json_response(ngx.HTTP_NOT_FOUND, {
        success = false,
        error = "Endpoint not found: " .. uri,
        available_endpoints = { "/redis", "/redis/info", "/redis/health" }
    })
end

-- Execute
main()